# Verify device placement order: .to(dev) BEFORE optimizer construction
python3 -c "
lines = open('train.py').readlines()
to_dev_line = None
optim_line = None
for i, line in enumerate(lines):
    if '.to(dev)' in line and 'student' in line and to_dev_line is None:
        to_dev_line = (i+1, line.strip())
    if 'optimizer = Adafactor' in line and optim_line is None:
        optim_line = (i+1, line.strip())
print('student.to(dev) at line:', to_dev_line)
print('optimizer = Adafactor at line:', optim_line)
if to_dev_line and optim_line:
    if to_dev_line[0] < optim_line[0]:
        print('CORRECT: model.to(device) before optimizer()')
    else:
        print('ERROR: optimizer before model.to(device)!')
"

